mapper.select:


        WITH first_events AS (
            SELECT e.*,
                ROW_NUMBER() OVER (
                  PARTITION BY outb_posx, outb_posy, evt_typ_cd
                  ORDER BY evt_outb_dtm ASC
              ) AS rn
            FROM xeus.v_mon_evet_list e
            WHERE 1=1


               AND (
	               e.evt_typ_cd = #{GUL}
	               OR e.evt_typ_cd = #{PORT}
	               OR e.evt_typ_cd = #{CORN}
	               OR e.evt_typ_cd = #{CRACK}
	               OR e.evt_typ_cd = #{NAK}
               )



				AND e.usvc_outb_id = #{usvcOutbId}


				AND e.usvc_outb_id = #{uSvcOutbId}



				AND e.evt_svc_nm = #{evtSvcNm}


				AND e.evt_svc_nm = #{statEvetNm}



				AND e.evt_typ = #{evtTyp}


				AND e.evt_typ = #{statEvetType}


				 AND e.evt_typ_cd = ANY(string_to_array(#{evtTypCd}, ','))


				AND e.evt_typ_cd = #{statEvetTypCd}



				AND e.msg_typ_cd = #{msgTypCd}


				AND e.msg_typ_cd = #{statMsgTypCd}



				AND e.evt_nm = #{evtNm}


				AND e.evt_nm = #{statEvetNm}



				AND e.evt_cntn = #{evtCntn}


				AND e.evt_cntn = #{statEvetCntn}



				AND e.outb_pos_nm = #{outbPosNm}



				AND e.outb_posx = #{outbPosx}::numeric



				AND e.outb_posy = #{outbPosy}::numeric



				AND e.evt_outb_dtm = #{evtOutbDtm}






               AND RPAD(evt_outb_dtm, 17, '0')::numeric  >=  RPAD(#{startDat}, 17, '0')::numeric


               AND RPAD(evt_outb_dtm, 17, '0')::numeric  <=  RPAD(#{endDat}, 17, '0')::numeric



				AND e.evt_clr_dtm = #{evtClrDtm}


				AND e.evt_clr_dtm = #{statEvetClrDtm}



				AND e.evt_proc_cd = #{evtProcCd}


				AND e.evt_proc_cd = #{procSt}



				AND e.evt_actn_dtm = #{evtActnDtm}


				AND e.evt_actn_dtm = #{statEvetActnDtm}



				AND e.evt_actn_usrid = #{evtActnUsrid}


				AND e.evt_actn_usrid = #{statEvetActnMn}



				AND e.evt_actn_cntn = #{evtActnCntn}


				AND e.evt_actn_cntn = #{statEvetActnCntn}



				AND e.test_yn = #{testYn}


				AND e.test_yn = #{isTest}



				AND e.evt_json = #{evtJson}


				AND e.evt_json = #{etcCntn}



               AND e.type = #{type}



            ),
            keep_events AS (
                SELECT fe.*
                FROM first_events fe
                WHERE rn = 1
            ),
               excluded_events AS (
                SELECT k.usvc_outb_id AS keeper_id,
                       sub.usvc_outb_id AS excluded_id
                FROM keep_events k
                JOIN keep_events sub
                  ON sub.usvc_outb_id <> k.usvc_outb_id
                 AND (sub.outb_posx, sub.outb_posy) <> (k.outb_posx, k.outb_posy)
                 AND trim(sub.evt_typ_cd) = trim(k.evt_typ_cd)
                 AND ST_DWithin(
                       ST_Transform(k._geometry, 5186),
                       ST_Transform(sub._geometry, 5186),
                       COALESCE((k.evt_json::json->>'dist')::numeric, 0)
                 )
            )
            SELECT ke.*
            FROM keep_events ke
            WHERE ke.usvc_outb_id NOT IN (
                SELECT excluded_id
                FROM excluded_events
            )



                  ${sortCol} ${sortTyp}


                  evt_outb_dtm desc




            LIMIT ${limit} OFFSET ${offset}

